/** Categories for the feat picker — derived from each feat so the constructor
 *  can group feats into sub-sections (origin / fighting style / general /
 *  dragon gifts / epic boons) without tagging every entry by hand. */
export function featCategory(f: FeatBuild): string {
  if (f.id.startsWith('gift-')) return 'Драконьи дары'
  if (f.id.startsWith('boon-') || f.prereq === '19-й уровень') return 'Эпические дары (с 19 ур.)'
  if (f.prereq === 'Способность класса «Боевой стиль»') return 'Боевой стиль'
  if (f.prereq === '4-й уровень') return 'Общие черты (с 4 ур.)'
  return 'Черты происхождения'
}

/** Lookup a feat entry by its display name (case-insensitive). */
export function featByName(name: string): FeatBuild | undefined {
  const k = name.trim().toLowerCase()
  return FEAT_BUILDS.find((f) => f.name.toLowerCase() === k)
}

